  w8d1:[{word:"Operating",phonetic:"אוֹפֶּרֵיְיטִינְג",meaning:"הַפְעָלָה",visual:"⚙️",exp:"מתייחס להפעלה או תפעול של מערכת או מכונה.",engEx:"The Operating System serves as the bridge between the user and the hardware.",hebEx:"מערכת ההפעלה משמשת כגשר בין המשתמש לחומרה."},{word:"Bridge",phonetic:"בְּרִידְג'",meaning:"גֶּשֶׁר",visual:"🌉",exp:"מבנה המחבר בין שני צדדים, פיזי או מטאפורי.",engEx:"The OS serves as the bridge between the user and the computer's hardware.",hebEx:"מערכת ההפעלה משמשת כגשר בין המשתמש לחומרת המחשב."},{word:"Hardware",phonetic:"הָארְדְוֶוֶר",meaning:"חוּמְרָה",visual:"🖥️",exp:"הרכיבים הפיזיים של המחשב כמו מעבד, זיכרון ומסך.",engEx:"The operating system communicates with the computer's hardware.",hebEx:"מערכת ההפעלה מתקשרת עם חומרת המחשב."},{word:"Software",phonetic:"סוֹפְטְוֶוֶר",meaning:"תּוֹכְנָה",visual:"💿",exp:"תוכניות ויישומים הפועלים על המחשב, בניגוד לחומרה.",engEx:"Most people use computers without thinking about the software that makes them work.",hebEx:"רוב האנשים משתמשים במחשבים מבלי לחשוב על התוכנה שגורמת להם לעבוד."},{word:"Coordinate",phonetic:"קוֹ-אוֹרְדִינֵייט",meaning:"לְתַאֵם",visual:"🤝",exp:"לארגן פעולות שונות כך שיעבדו יחד בהרמוניה.",engEx:"There is a complex system working behind the scenes to coordinate all activities.",hebEx:"ישנה מערכת מורכבת הפועלת מאחורי הקלעים לתאם את כל הפעילויות."},{word:"Complex",phonetic:"קוֹמְפְּלֶקְס",meaning:"מוּרְכָּב",visual:"🧩",exp:"דבר המורכב מחלקים רבים ומסובך להבנה.",engEx:"There is a complex system working behind the scenes.",hebEx:"ישנה מערכת מורכבת שפועלת מאחורי הקלעים."},{word:"Behind the scenes",phonetic:"בִּיהָאיְנְד דָּה סִינְס",meaning:"מֵאֲחוֹרֵי הַקְּלָעִים",visual:"🎬",exp:"ביטוי המתאר דברים שקורים ברקע, מבלי שרואים אותם.",engEx:"The OS works behind the scenes to manage all processes.",hebEx:"מערכת ההפעלה פועלת מאחורי הקלעים לניהול כל התהליכים."},{word:"Manage",phonetic:"מַנֵּג'",meaning:"לְנַהֵל",visual:"📋",exp:"לשלוט, לארגן ולפקח על משהו.",engEx:"The OS must manage processes, memory, files, and devices.",hebEx:"מערכת ההפעלה חייבת לנהל תהליכים, זיכרון, קבצים והתקנים."},{word:"Schedule",phonetic:"סְקֶדְיוּל",meaning:"לְתַזְמֵן / לוּחַ זְמַנִּים",visual:"📅",exp:"לקבוע סדר פעולות לפי זמן, או לוח זמנים מאורגן.",engEx:"The scheduler ensures that all programs run smoothly.",hebEx:"המתזמן מבטיח שכל התוכניות פועלות בצורה חלקה."},{word:"Processor",phonetic:"פְּרוֹסֶסוֹר",meaning:"מְעַבֵּד",visual:"🧠",exp:"הרכיב המרכזי במחשב שמבצע את כל החישובים.",engEx:"The OS decides how much processor time each process receives.",hebEx:"מערכת ההפעלה מחליטה כמה זמן מעבד כל תהליך מקבל."}],
